{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select the Pelvic CT Scan",
      "simple": "Choose the Pelvic Volume from the input list.",
      "detailed": "This step provides the CT scan of the pelvis that will be used for segmentation and planning. Select the appropriate volume from the list to proceed."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button.",
      "detailed": "The tool will automatically identify and segment the pelvic bone from the CT scan, creating a 3D model needed for fracture analysis and surgical planning. Click the button to start the segmentation."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fracture Lines",
      "simple": "Click the 'Run Step 2: Segment Fractures' button.",
      "detailed": "Automatically detect and segment the fracture lines of the pelvis. This step separates the bone into individual fracture fragments that will be used for reduction planning."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Unstable or Irrelevant Fragments",
      "simple": "Untick any fracture segments you wish to exclude from the planning.",
      "detailed": "You may choose to exclude small or non-critical fragments from the reduction plan to simplify the workflow. Untick the boxes next to segments that should not be included in the reduction or screw planning."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate a Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button.",
      "detailed": "The tool will generate an anatomical template based on the intact pelvis or a statistical shape model. This template serves as the target shape for fracture reduction."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fractures",
      "simple": "Click the 'Run Step 4: Register & Reduce' button.",
      "detailed": "Automatically align the fracture fragments to the template, simulating the reduction of the pelvis to its anatomical position. This step computes the optimal position for each fragment."
    },
    {
      "step_id": "cb_step_7",
      "title": "Decide on Manual Fragment Adjustment",
      "simple": "Choose whether to manually adjust a fragment or skip to screw planning.",
      "detailed": "If the automatic reduction is satisfactory, choose 'No' to proceed directly to screw planning. Otherwise, select 'Yes' to fine-tune the alignment of a specific fragment."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select a Fragment to Adjust",
      "simple": "Choose which fragment needs adjustment from the dropdown list.",
      "detailed": "Pick the fragment you wish to manually reposition or rotate. This allows precise correction of any residual displacement not captured by the automatic reduction."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Manually move and rotate the selected fragment to refine its alignment.",
      "detailed": "Fine-tune the fragment’s position and orientation for optimal anatomical reduction. Use the 3D viewer to achieve the best fit against surrounding bone."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Your Manual Adjustments",
      "simple": "Click the 'Apply adjustments' button to finalize the changes.",
      "detailed": "Confirm your manual repositioning of the fragment. The tool will update the reduction model with your adjustments."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Placement",
      "simple": "Click the 'Run Step 5: Plan Screws' button.",
      "detailed": "Automatically generate screw trajectories for fixation based on the reduced pelvis. This step provides a starting point for safe screw placement."
    },
    {
      "step_id": "cb_step_12",
      "title": "Decide on Screw Trajectory Editing",
      "simple": "Choose whether to edit the screw trajectories or stop here.",
      "detailed": "If the planned screws are acceptable, select 'No' to complete the workflow. If adjustments are needed, select 'Yes' to modify the trajectories."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Manually adjust the position and rotation of the screw trajectory lines.",
      "detailed": "Refine the planned screw paths to avoid critical structures such as nerves or vessels. Use the interactive lines to position each screw optimally."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edited Lines",
      "simple": "Click the 'Regenerate screw from edited lines' button.",
      "detailed": "Update the 3D screw models based on your manual trajectory adjustments. This finalizes the modified screw plan."
    },
    {
      "step_id": "cb_step_15",
      "title": "Finish Editing Screw Trajectories",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to return to the main workflow.",
      "detailed": "Conclude the screw trajectory editing session. The plan is now complete and ready for surgical use."
    }
  ]
}
